// 1. Définition des lancers avec leurs labels de couleur pour Foundry/DSN
// La syntaxe "1d6[couleur]" est interprétée nativement par Dice So Nice.
let r1 = await new Roll("1d6[red]").evaluate();
let r2 = await new Roll("1d6[black]").evaluate();
let r3 = await new Roll("1d6[white]").evaluate();

const results = [
  { val: r1.total, bg: "#cc0000", txt: "#ffffff" },
  { val: r2.total, bg: "#000000", txt: "#ffffff" },
  { val: r3.total, bg: "#ffffff", txt: "#000000", border: "1px solid #000" }
];

// 2. Affichage des dés en 3D (DSN écoute les messages de chat)
// On crée le message de chat. Dice So Nice interceptera les jets 
// et affichera les dés rouge, noir et blanc grâce aux tags ci-dessus.
let diceHtml = results.map(d => {
  let border = d.border ? `border: ${d.border};` : "border: none;";
  return `
    <div style="background:${d.bg}; color:${d.txt}; ${border} width:25px; height:25px; line-height:25px; text-align:center; border-radius:4px; font-size:1.1em; font-weight:bold; display:inline-block; margin-right:6px; box-shadow:1px 1px 2px rgba(0,0,0,0.3);">
      ${d.val}
    </div>`;
}).join("");

// 3. Envoi au Chat
ChatMessage.create({
  user: game.user._id,
  speaker: ChatMessage.getSpeaker(),
  // On passe les rolls originaux pour que DSN les détectent
  rolls: [r1, r2, r3],
  content: `
    <div style="display: flex; padding: 1em; padding-left: 33%; align-items: center;">
      ${diceHtml}
    </div>
  `
});
